	@Test
	void queryTemplateHashIsStableAcrossEquivalentOperandAndFilterOrder() throws Exception {
		LearnedQueryJoinOptimizer optimizer = new LearnedQueryJoinOptimizer(new EvaluationStatistics(),
				new EmptyTripleSource(), new NoopStatsProvider());
		Object visitor = newLearnedJoinVisitor(optimizer);

		TupleExpr left = new StatementPattern(Var.of("enc"),
				Var.of("p1", SimpleValueFactory.getInstance().createIRI("urn:test:hasCondition")),
				Var.of("cond"));
		TupleExpr right = new StatementPattern(Var.of("cond"),
				Var.of("p2", SimpleValueFactory.getInstance().createIRI("urn:test:code")),
				Var.of("condCode"));
		ValueExpr leftFilter = new Compare(Var.of("condCode"),
				new ValueConstant(SimpleValueFactory.getInstance().createLiteral("DX-200")), CompareOp.EQ);
		ValueExpr rightFilter = new Compare(Var.of("condCode"),
				new ValueConstant(SimpleValueFactory.getInstance().createLiteral("DX-201")), CompareOp.EQ);

		String firstHash = queryTemplateHash(visitor, List.of(left, right), List.of(leftFilter, rightFilter));
		String secondHash = queryTemplateHash(visitor, List.of(right, left), List.of(rightFilter, leftFilter));

		assertEquals(firstHash, secondHash);
	}

	private static JoinPlanCandidate candidate(String signature, double estimatedCost, double totalUncertainty) {
		StatementPattern pattern = new StatementPattern(Var.of("s"),
				Var.of("p", SimpleValueFactory.getInstance().createIRI("urn:test:" + signature)), Var.of("o"));
		CardinalityEstimateBreakdown breakdown = new CardinalityEstimateBreakdown(0, 0, estimatedCost,
				estimatedCost, totalUncertainty);
		return JoinPlanCandidate.of(List.of(pattern), List.of(0), signature, estimatedCost, estimatedCost,
				List.of(breakdown));
	}

	private static Object newLearnedJoinVisitor(LearnedQueryJoinOptimizer optimizer) throws Exception {
		Class<?> visitorClass = Class.forName(LearnedQueryJoinOptimizer.class.getName() + "$LearnedJoinVisitor");
		Constructor<?> constructor = visitorClass.getDeclaredConstructor(LearnedQueryJoinOptimizer.class, Dataset.class,
				BindingSet.class);
		constructor.setAccessible(true);
		return constructor.newInstance(optimizer, null, EmptyBindingSet.getInstance());
	}

	private static SelectionResult selectCandidateDecision(Object visitor, PlanForceMode forceMode, String templateHash,
			List<JoinPlanCandidate> candidates) throws Exception {
		Method method = visitor.getClass()
				.getDeclaredMethod("selectCandidateIndex", PlanForceMode.class,
						String.class, List.class);
		method.setAccessible(true);
		Object selection = method.invoke(visitor, forceMode, templateHash, candidates);
		if (selection instanceof Integer) {
			return new SelectionResult((int) selection, "not-applicable", "none", "not-applicable", Double.NaN,
					Double.NaN);
		}
		return new SelectionResult(
				readIntField(selection, "selectedCandidateIndex"),
				readStringField(selection, "stabilityDecision"),
				readStringField(selection, "stabilitySource"),
				readStringField(selection, "stabilitySwitchTrigger"),
				readDoubleField(selection, "stabilityImprovementRatio"),
				readDoubleField(selection, "stabilityUncertaintyDelta"));
	}

	private static String queryTemplateHash(Object visitor, List<TupleExpr> joinArgs, List<ValueExpr> filters)
			throws Exception {
		Method method = visitor.getClass().getDeclaredMethod("queryTemplateHash", List.class, List.class);
		method.setAccessible(true);
		return (String) method.invoke(visitor, joinArgs, filters);
	}

	private static int readIntField(Object source, String fieldName) throws Exception {
		Field field = source.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return (int) field.get(source);
	}

	private static String readStringField(Object source, String fieldName) throws Exception {
		Field field = source.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return (String) field.get(source);
	}

	private static double readDoubleField(Object source, String fieldName) throws Exception {
		Field field = source.getClass().getDeclaredField(fieldName);
		field.setAccessible(true);
		return (double) field.get(source);
	}

	private static final class SelectionResult {
		private final int selectedCandidateIndex;
		private final String stabilityDecision;
		private final String stabilitySource;
		private final String stabilitySwitchTrigger;
		private final double stabilityImprovementRatio;
		private final double stabilityUncertaintyDelta;

		private SelectionResult(int selectedCandidateIndex, String stabilityDecision, String stabilitySource,
				String stabilitySwitchTrigger,
				double stabilityImprovementRatio, double stabilityUncertaintyDelta) {
			this.selectedCandidateIndex = selectedCandidateIndex;
			this.stabilityDecision = stabilityDecision;
			this.stabilitySource = stabilitySource;
			this.stabilitySwitchTrigger = stabilitySwitchTrigger;
			this.stabilityImprovementRatio = stabilityImprovementRatio;
			this.stabilityUncertaintyDelta = stabilityUncertaintyDelta;
		}
	}

	@SuppressWarnings("unchecked")
	private static void clearExploreWinnerCache() throws Exception {
		Field field = LearnedQueryJoinOptimizer.class.getDeclaredField("EXPLORE_WINNER_CACHE");
		field.setAccessible(true);
		Map<String, ?> cache = (Map<String, ?>) field.get(null);
		cache.clear();
	}

